@startuml

class Config {
  {field} - properties : Properties
  {field} - {static} config : Config
  {method} - Config()
  {method} + {static} getConfig() : Config
}

class DBConnectionTest {
  {method} + hashCodeTest() : void
  {method} + performanceTest() : void
  {method} + DBH2Test() : void
}

class DBConnection {
  {field} - connection : Connection
  {field} - {static} dbConnection : DBConnection
  {method} - DBConnection()
  {method} + {static} getDBConnection() : DBConnection
  {method} + getConnection() : Connection
}

Config "1" <--o "1" Config
DBConnection "1" <--* "1" Config
DBConnectionTest ..> DBConnection
DBConnection "1" <--o "1" DBConnection

@enduml
